+                ),
+                input_schema: json!({"type": "object"}),
+                output_schema: json!({"type": "object"}),
+                capability: CapabilityId::from_static("test.op.invoke"),
+                risk_level: RiskLevel::Low,
+                safety_tier: SafetyTier::Safe,
