+                schema: json!({"type": "object"}),
+                requires_ack: false,
+            }],
+            resource_types: vec![],
+            auth_caps: None,
+            event_caps: Some(EventCaps {
+                streaming: true,
+                replay: false,
+                min_buffer_events: 0,
+                requires_ack: false,
+            }),
+        }
+    }
